}

export declare type OpenGraphMetadata = {
    type?: string;
    title?: string;
    description?: string;
    site_name?: string;
    url?: string;
    images: OpenGraphMetadataImage[];
};

export declare type PostPreviewMetadata = {
    post_id: string;
    post?: Post;
    channel_display_name: string;
    team_name: string;
    channel_type: ChannelType;
    channel_id: string;
