{"content":[{"type":"text","text":"// Copyright (c) 2015-present Mattermost, Inc. All Rights Reserved.
// See LICENSE.txt for license information.

import React from 'react';
import classNames from 'classnames';
import {Modal} from 'react-bootstrap';
import {FormattedMessage} from 'react-intl';

import {FocusTrap} from '@mattermost/components';

import './generic_modal.scss';

export type Props = {
    className?: string;
    onExited: () => void;
    modalHeaderText?: React.ReactNode;
    show?: boolean;
    handleCancel?: () => void;
    handleConfirm?: () => void;
    handleEnterKeyPress?: () => void;
    handleKeydown?: (event?: React.KeyboardEvent<HTMLDivElement>) => void;
    confirmButtonText?: React.ReactNode;
    confirmButtonClassName?: string;
    cancelButtonText?: React.ReactNode;
    cancelButtonClassName?: string;
    isConfirmDisabled?: boolean;
    isDeleteModal?: boolean;
    id: string;
    autoCloseOnCancelButton?: boolean;
    autoCloseOnConfirmButton?: boolean;

    /**
     * If false, bootrap's Modal will not enforce focus on the modal and will
     * transfer the mechanism to the FocusTrap component instead.
     */
    enforceFocus?: boolean;
    container?: React.ReactNode | React.ReactNodeArray;
    ariaLabel?: string;
    errorText?: string;
    compassDesign?: boolean;
    backdrop?: boolean;
    backdropClassName?: string;
    headerButton?: React.ReactNode;
    tabIndex?: number;
    children: React.ReactNode;
    keyboardEscape?: boolean;
};

type State = {
    show: boolean;
    isFocalTrapActive: boolean;
};

const ModalHeader = ({children}: { children: React.ReactNode }) => (
    <Modal.Header closeButton={true}>{children}</Modal.Header>
);

const ModalBody = ({children}: { children: React.ReactNode }) => (
    <Modal.Body>{children}</Modal.Body>
);

const ModalFooter = ({children}: { children: React.ReactNode }) => (
    <Modal.Footer>{children}</Modal.Footer>
);

export class GenericModal extends React.PureComponent<Props, State> {
    static Header = ModalHeader;
    static Body = ModalBody;
    static Footer = ModalFooter;

    static defaultProps: Partial<Props> = {
        show: true,
        id: 'genericModal',
        autoCloseOnCancelButton: true,
        autoCloseOnConfirmButton: true,
        enforceFocus: true,
        keyboardEscape: true,
    };

    constructor(props: Props) {
        super(props);

        this.state = {
            show: props.show!,
            isFocalTrapActive: false,
        };
    }

    onHide = () => {
        this.setState({show: false});
    };

    handleCancel = (event: React.MouseEvent<HTMLButtonElement, MouseEvent>) => {
        event.preventDefault();
        if (this.props.autoCloseOnCancelButton) {
            this.onHide();
        }
        if (this.props.handleCancel) {
            this.props.handleCancel();
        }
    };

    handleConfirm = (
        event: React.MouseEvent<HTMLButtonElement, MouseEvent>,
    ) => {
        event.preventDefault();
        if (this.props.autoCloseOnConfirmButton) {
            this.onHide();
        }
        if (this.props.handleConfirm) {
            this.props.handleConfirm();
        }
    };

    private onEnterKeyDown = (event: React.KeyboardEvent<HTMLDivElement>) => {
        if (event.key === 'Enter') {
            if (this.props.autoCloseOnConfirmButton) {
                this.onHide();
            }
            if (this.props.handleEnterKeyPress) {
                this.props.handleEnterKeyPress();
            }
        }
        this.props.handleKeydown?.(event);
    };

    private handleShow = () => {
        if (this.props.enforceFocus === false) {
            this.setState({isFocalTrapActive: true});
        }
    };

    render() {
        let confirmButton;
        if (this.props.handleConfirm) {
            const isConfirmOrDeleteClassName = this.props.isDeleteModal ? 'delete' : 'confirm';
            let confirmButtonText: React.ReactNode = (
                <FormattedMessage
                    id='generic_modal.confirm'
                    defaultMessage='Confirm'
                />
            );
            if (this.props.confirmButtonText) {
                confirmButtonText = this.props.confirmButtonText;
            }

            confirmButton = (
                <button
                    type='submit'
                    className={classNames(
                        'GenericModal__button',
                        isConfirmOrDeleteClassName,
                        this.props.confirmButtonClassName,
                        {
                            disabled: this.props.isConfirmDisabled,
                        },
                    )}
                    onClick={this.handleConfirm}
                    disabled={this.props.isConfirmDisabled}
                >
                    {confirmButtonText}
                </button>
            );
        }

        let cancelButton;
        if (this.props.handleCancel) {
            let cancelButtonText: React.ReactNode = (
                <FormattedMessage
                    id='generic_modal.cancel'
                    defaultMessage='Cancel'
                />
            );
            if (this.props.cancelButtonText) {
                cancelButtonText = this.props.cancelButtonText;
            }

            cancelButton = (
                <button
                    type='button'
                    className={classNames(
                        'GenericModal__button cancel',
                        this.props.cancelButtonClassName,
                    )}
                    onClick={this.handleCancel}
                >
                    {cancelButtonText}
                </button>
            );
        }

        const headerText = this.props.modalHeaderText && (
            <div className='GenericModal__header'>
                <h1 id='genericModalLabel'>{this.props.modalHeaderText}</h1>
                {this.props.headerButton}
            </div>
        );

        const isFocusTrapActive =
            this.props.enforceFocus === false ? this.state.isFocalTrapActive : false;

        return (
            <Modal
                id={this.props.id}
                role='dialog'
                aria-label={this.props.ariaLabel}
                aria-labelledby={
                    this.props.ariaLabel ? undefined : 'genericModalLabel'
                }
                dialogClassName={classNames(
                    'a11y__modal GenericModal',
                    {GenericModal__compassDesign: this.props.compassDesign},
                    this.props.className,
                )}
                show={this.state.show}
                onShow={this.handleShow}
                restoreFocus={true}
                enforceFocus={this.props.enforceFocus}
                onHide={this.onHide}
                onExited={this.props.onExited}
                backdrop={this.props.backdrop}
                backdropClassName={this.props.backdropClassName}
                container={this.props.container}
                keyboard={this.props.keyboardEscape}
            >
                <FocusTrap active={isFocusTrapActive}>
                    <div
                        onKeyDown={this.onEnterKeyDown}
                        tabIndex={this.props.tabIndex || 0}
                        className='GenericModal__wrapper-enter-key-press-catcher'
                    >
                        <GenericModal.Header>
                            {this.props.compassDesign && headerText}
                        </GenericModal.Header>
                        <GenericModal.Body>
                            {this.props.compassDesign ? this.props.errorText && (
                                <div className='genericModalError'>
                                    <i className='icon icon-alert-outline'/>
                                    <span>{this.props.errorText}</span>
                                </div>
                            ) : headerText}
                            <div className='GenericModal__body'>
                                {this.props.children}
                            </div>
                        </GenericModal.Body>
                        {(cancelButton || confirmButton) && (
                            <GenericModal.Footer>
                                {cancelButton}
                                {confirmButton}
                            </GenericModal.Footer>
                        )}
                    </div>
                </FocusTrap>
            </Modal>
        );
    }
}

export default GenericModal;
"}]}

